import React, { useState, useEffect } from 'react';
import { videoService } from '../../services/videoService';

const VideoManager = () => {
    const [videos, setVideos] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showAddForm, setShowAddForm] = useState(false);
    const [editingVideo, setEditingVideo] = useState(null);
    const [message, setMessage] = useState({ type: '', text: '' });
    const [newVideo, setNewVideo] = useState({
        title: '',
        description: '',
        video_url: '',
        video_type: 'youtube',
        duration: '',
        status: 'active',
        display_order: 0
    });

    useEffect(() => {
        loadVideos();
    }, []);

    const loadVideos = async () => {
        try {
            const response = await videoService.getAll(false);
            if (response.success) {
                setVideos(response.data);
            }
        } catch (error) {
            showMessage('error', 'Failed to load videos');
        } finally {
            setLoading(false);
        }
    };

    const showMessage = (type, text) => {
        setMessage({ type, text });
        setTimeout(() => setMessage({ type: '', text: '' }), 3000);
    };

    const handleAddVideo = async () => {
        if (!newVideo.title || !newVideo.video_url) {
            showMessage('error', 'Please fill title and video URL');
            return;
        }

        try {
            const response = await videoService.create(newVideo);
            if (response.success) {
                showMessage('success', 'Video added successfully');
                setShowAddForm(false);
                setNewVideo({
                    title: '',
                    description: '',
                    video_url: '',
                    video_type: 'youtube',
                    duration: '',
                    status: 'active',
                    display_order: 0
                });
                loadVideos();
            }
        } catch (error) {
            showMessage('error', error.response?.data?.message || 'Failed to add video');
        }
    };

    const handleUpdateVideo = async () => {
        if (!editingVideo.title || !editingVideo.video_url) {
            showMessage('error', 'Please fill title and video URL');
            return;
        }

        try {
            const response = await videoService.update(editingVideo.id, editingVideo);
            if (response.success) {
                showMessage('success', 'Video updated successfully');
                setEditingVideo(null);
                loadVideos();
            }
        } catch (error) {
            showMessage('error', error.response?.data?.message || 'Failed to update video');
        }
    };

    const handleDeleteVideo = async (id, title) => {
        if (window.confirm(`Are you sure you want to delete "${title}"?`)) {
            try {
                const response = await videoService.delete(id);
                if (response.success) {
                    showMessage('success', 'Video deleted successfully');
                    loadVideos();
                }
            } catch (error) {
                showMessage('error', error.response?.data?.message || 'Failed to delete video');
            }
        }
    };

    const getYouTubeEmbedUrl = (url) => {
        if (url.includes('youtube.com/watch?v=')) {
            const videoId = url.split('v=')[1].split('&')[0];
            return `https://www.youtube.com/embed/${videoId}`;
        }
        if (url.includes('youtu.be/')) {
            const videoId = url.split('youtu.be/')[1].split('?')[0];
            return `https://www.youtube.com/embed/${videoId}`;
        }
        return url;
    };

    if (loading) {
        return <div className="loading-spinner">Loading videos...</div>;
    }

    return (
        <div className="video-manager">
            <div className="section-header">
                <h2><i className="fas fa-video"></i> Video Manager</h2>
                <button onClick={() => setShowAddForm(!showAddForm)} className="btn-primary">
                    <i className="fas fa-plus"></i> Add Video
                </button>
            </div>

            {message.text && (
                <div className={`message ${message.type}`}>
                    <i className={`fas fa-${message.type === 'success' ? 'check-circle' : 'exclamation-circle'}`}></i>
                    {message.text}
                </div>
            )}

            {showAddForm && (
                <div className="form-modal">
                    <div className="form-card">
                        <h3>Add New Video</h3>
                        <div className="form-grid">
                            <div className="form-field">
                                <label>Title *</label>
                                <input type="text" value={newVideo.title} onChange={(e) => setNewVideo({...newVideo, title: e.target.value})} />
                            </div>
                            <div className="form-field">
                                <label>Video Type</label>
                                <select value={newVideo.video_type} onChange={(e) => setNewVideo({...newVideo, video_type: e.target.value})}>
                                    <option value="youtube">YouTube</option>
                                    <option value="vimeo">Vimeo</option>
                                    <option value="local">Local</option>
                                </select>
                            </div>
                            <div className="form-field">
                                <label>Video URL *</label>
                                <input type="url" placeholder="https://..." value={newVideo.video_url} onChange={(e) => setNewVideo({...newVideo, video_url: e.target.value})} />
                            </div>
                            <div className="form-field">
                                <label>Description</label>
                                <textarea rows="3" value={newVideo.description} onChange={(e) => setNewVideo({...newVideo, description: e.target.value})}></textarea>
                            </div>
                            <div className="form-field">
                                <label>Duration (seconds)</label>
                                <input type="number" value={newVideo.duration} onChange={(e) => setNewVideo({...newVideo, duration: e.target.value})} />
                            </div>
                            <div className="form-field">
                                <label>Display Order</label>
                                <input type="number" value={newVideo.display_order} onChange={(e) => setNewVideo({...newVideo, display_order: e.target.value})} />
                            </div>
                            <div className="form-field">
                                <label>Status</label>
                                <select value={newVideo.status} onChange={(e) => setNewVideo({...newVideo, status: e.target.value})}>
                                    <option value="active">Active</option>
                                    <option value="inactive">Inactive</option>
                                </select>
                            </div>
                        </div>
                        <div className="form-actions">
                            <button onClick={handleAddVideo} className="save-btn"><i className="fas fa-save"></i> Add Video</button>
                            <button onClick={() => setShowAddForm(false)} className="cancel-btn">Cancel</button>
                        </div>
                    </div>
                </div>
            )}

            <div className="videos-grid">
                {videos.map(video => (
                    <div key={video.id} className="video-card">
                        {editingVideo?.id === video.id ? (
                            <div className="edit-form">
                                <input type="text" value={editingVideo.title} onChange={(e) => setEditingVideo({...editingVideo, title: e.target.value})} placeholder="Title" />
                                <select value={editingVideo.video_type} onChange={(e) => setEditingVideo({...editingVideo, video_type: e.target.value})}>
                                    <option value="youtube">YouTube</option>
                                    <option value="vimeo">Vimeo</option>
                                </select>
                                <input type="url" value={editingVideo.video_url} onChange={(e) => setEditingVideo({...editingVideo, video_url: e.target.value})} placeholder="URL" />
                                <textarea value={editingVideo.description} onChange={(e) => setEditingVideo({...editingVideo, description: e.target.value})} placeholder="Description" rows="2"></textarea>
                                <select value={editingVideo.status} onChange={(e) => setEditingVideo({...editingVideo, status: e.target.value})}>
                                    <option value="active">Active</option>
                                    <option value="inactive">Inactive</option>
                                </select>
                                <div className="edit-actions">
                                    <button onClick={handleUpdateVideo} className="save-btn"><i className="fas fa-check"></i> Save</button>
                                    <button onClick={() => setEditingVideo(null)} className="cancel-btn">Cancel</button>
                                </div>
                            </div>
                        ) : (
                            <>
                                <div className="video-thumbnail">
                                    <iframe src={getYouTubeEmbedUrl(video.video_url)} title={video.title} frameBorder="0" allowFullScreen></iframe>
                                </div>
                                <div className="video-info">
                                    <h4>{video.title}</h4>
                                    <p>{video.description}</p>
                                    <div className="video-meta">
                                        <span><i className="fas fa-play-circle"></i> {video.video_type}</span>
                                        <span className={`status-${video.status}`}>{video.status}</span>
                                    </div>
                                </div>
                                <div className="video-actions">
                                    <button onClick={() => setEditingVideo(video)} className="edit-btn"><i className="fas fa-edit"></i></button>
                                    <button onClick={() => handleDeleteVideo(video.id, video.title)} className="delete-btn"><i className="fas fa-trash"></i></button>
                                </div>
                            </>
                        )}
                    </div>
                ))}
            </div>

            {videos.length === 0 && !loading && (
                <div className="empty-state">
                    <i className="fas fa-video"></i>
                    <h3>No Videos</h3>
                    <p>Add promotional videos to display on the TV dashboard.</p>
                </div>
            )}
        </div>
    );
};

export default VideoManager;
